function Gallery() {
  const images = [
    "/assets/roof1.jpg",
    "/assets/roof2.jpg",
    "/assets/roof3.jpg",
    "/assets/roof4.jpg",
    "/assets/roof5.jpg",
    "/assets/roof6.jpg",
  ];

  return (
    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4 p-4">
      {images.map((src, idx) => (
        <img
          key={idx}
          src={src}
          alt={`Project ${idx + 1}`}
          className="rounded-lg shadow-md hover:scale-105 transition-transform"
        />
      ))}
    </div>
  );
}

export default Gallery;
